import { SeedApiClient } from "@fern/literal";

const client = new SeedApiClient({ environment: "YOUR_BASE_URL" });
await client.headers.send({
    "X-Endpoint-Version": "02-12-2024",
    "X-Async": true,
    query: "query"
});

import { SeedApiClient } from "@fern/literal";

const client = new SeedApiClient({ environment: "YOUR_BASE_URL" });
await client.inlined.send({
    prompt: "You are a helpful assistant",
    query: "query",
    stream: true,
    aliasedContext: "You're super wise",
    objectWithLiteral: {
        nestedLiteral: {
            myLiteral: "How super cool"
        }
    }
});

import { SeedApiClient } from "@fern/literal";

const client = new SeedApiClient({ environment: "YOUR_BASE_URL" });
await client.path.send({
    id: "123"
});

import { SeedApiClient } from "@fern/literal";

const client = new SeedApiClient({ environment: "YOUR_BASE_URL" });
await client.query.send({
    prompt: "You are a helpful assistant",
    alias_prompt: "You are a helpful assistant",
    query: "query",
    stream: true,
    alias_stream: true
});

import { SeedApiClient } from "@fern/literal";

const client = new SeedApiClient({ environment: "YOUR_BASE_URL" });
await client.reference.send({
    prompt: "You are a helpful assistant",
    query: "query",
    stream: true,
    ending: "\\$ending",
    context: "You're super wise",
    containerObject: {
        nestedObjects: [{
                literal1: "literal1",
                literal2: "literal2",
                strProp: "strProp"
            }]
    }
});
